#!/bin/bash

ME=$(basename "${BASH_SOURCE[0]}")
DIR=$(cd "$(dirname "${BASH_SOURCE[0]}")" &>/dev/null && pwd)

PREVIEW_COMMAND="$DIR/$ME render {+}"

function split () {
    printf '%s\n' "$@"
}

function render () {
    cut -f2 -d' ' |
        tr -d '\'n |
        perl -CS -pe 's/..\K(?=.)/\N{U+200D}/g'
}

function main () {
    if [ "$1" = 'render' ]; then
        shift
        split "$@"
    else
        base64 --decode <<EOF | bzcat | fzf -0 -m --preview="$PREVIEW_COMMAND"

EOF
    fi
}

main "$@" | render
